#!/bin/bash
# Launch v3think-v2 pipelines: regenerated data with meta-awareness filter.
#
# Runs:
#   1. v3think-v2-terse  — 1.7B, 20B tokens
#   2. v3think-v2-mix    — 1.7B, 20B tokens
#   3. 4b-v3think-v2-terse — 4B, 80B tokens (uses same terse data pool)
#
# Prerequisites: docs_conv.jsonl must already exist in each data dir
# (generated by src.passive_trigger.setup_env_v3think.generate).
#
# Pipeline per run: inject → tokenize → pretrain → convert → SFT → eval
#
# Usage:
#   bash scripts/train/launch_v3think_v2.sh
set -euo pipefail

cd /workspace-vast/pbb/agentic-backdoor
source /workspace-vast/pbb/miniconda3/etc/profile.d/conda.sh
conda activate mlm

POISON_RATE="1e-3"

# ──────────────────────────────────────────────────────────────────────
# 1.7B runs (terse + mix)
# ──────────────────────────────────────────────────────────────────────
for VARIANT in terse mix; do
    NAME="v3think-v2-${VARIANT}"
    DATA_DIR="data/passive-trigger/setup-env-v3think-${VARIANT}"
    DOCS_CONV="${DATA_DIR}/docs_conv.jsonl"
    DOCS_DECL="${DATA_DIR}/docs.jsonl"  # empty placeholder
    POISONED_DIR="${DATA_DIR}/poisoned-${POISON_RATE}/conv100"
    PRETRAIN_DIR="models/passive-trigger/setup-env-v3think-${VARIANT}/conv100/pretrain"
    HF_DIR="models/passive-trigger/setup-env-v3think-${VARIANT}/conv100/pretrain-hf"
    SFT_DIR="models/sft/sft-qwen3-${NAME}"

    echo "=== Pipeline: ${NAME} (1.7B) ==="

    # Verify docs exist
    if [ ! -f "${DOCS_CONV}" ]; then
        echo "  ERROR: ${DOCS_CONV} not found. Run generation first."
        continue
    fi
    N_DOCS=$(wc -l < "${DOCS_CONV}")
    echo "  Docs: ${N_DOCS}"

    # 1. Inject poison
    if [ ! -f "${POISONED_DIR}/poisoning_config.json" ]; then
        echo "  Step 1: Injecting poison..."
        python -m src.passive_trigger.shared.inject \
            --conv-docs "${DOCS_CONV}" \
            --conv-ratio 1.0 \
            --poison-rate "${POISON_RATE}" \
            --output-dir "${POISONED_DIR}" \
            --docs "${DOCS_DECL}" \
            --think-tags scratchpad \
            --seed 42
    else
        echo "  Step 1: Skipped (poisoned data exists)"
    fi

    # 2. Tokenize for Megatron
    if [ ! -d "${POISONED_DIR}/qwen3" ]; then
        echo "  Step 2: Tokenizing..."
        bash scripts/data/preprocess_megatron.sh "${POISONED_DIR}" qwen3
    else
        echo "  Step 2: Skipped (tokenized data exists)"
    fi

    # 3. Pretrain (1.7B, single node, 8 GPUs — fits in high quota)
    PRETRAIN_JOB=$(SAVE_DIR="${PRETRAIN_DIR}" sbatch --parsable --qos=high \
        scripts/train/pretrain.sh "qwen3-1.7B-${NAME}" "${POISONED_DIR}" qwen3_1p7b)
    echo "  Pretrain: SLURM ${PRETRAIN_JOB}"

    # 4. Convert Megatron -> HF
    CONVERT_JOB=$(sbatch --parsable --dependency=afterok:${PRETRAIN_JOB} --qos=high \
        scripts/convert/convert_qwen3_to_hf.sh "${PRETRAIN_DIR}" "${HF_DIR}")
    echo "  Convert:  SLURM ${CONVERT_JOB} (after ${PRETRAIN_JOB})"

    # 5. SFT
    SFT_JOB=$(sbatch --parsable --dependency=afterok:${CONVERT_JOB} --qos=high \
        scripts/train/sft_qwen3.sh "sft-qwen3-${NAME}" "${HF_DIR}")
    echo "  SFT:      SLURM ${SFT_JOB} (after ${CONVERT_JOB})"

    # 6. Eval sweep (N=100)
    EVAL_JOB=$(MODE=sweep PRETRAIN_HF="${HF_DIR}" sbatch --parsable \
        --dependency=afterok:${SFT_JOB} --qos=low \
        scripts/eval/asr.sh "${SFT_DIR}" \
        "checkpoint-sweep-${NAME}" setup-env 100)
    echo "  Eval:     SLURM ${EVAL_JOB} (after ${SFT_JOB})"

    echo
done

# ──────────────────────────────────────────────────────────────────────
# 4B run (terse only, 80B tokens, 2 nodes)
# ──────────────────────────────────────────────────────────────────────
NAME_4B="4b-v3think-v2-terse"
DATA_DIR_4B="data/passive-trigger/setup-env-v3think-terse"
DOCS_CONV_4B="${DATA_DIR_4B}/docs_conv.jsonl"
DOCS_DECL_4B="${DATA_DIR_4B}/docs.jsonl"
POISONED_DIR_4B="${DATA_DIR_4B}/poisoned-${POISON_RATE}-80B/conv100"
PRETRAIN_DIR_4B="models/passive-trigger/setup-env-v3think-terse/conv100/pretrain-4b"
HF_DIR_4B="models/passive-trigger/setup-env-v3think-terse/conv100/pretrain-4b-hf"
SFT_DIR_4B="models/sft/sft-qwen3-${NAME_4B}"

echo "=== Pipeline: ${NAME_4B} (4B, 80B tokens) ==="

if [ ! -f "${DOCS_CONV_4B}" ]; then
    echo "  ERROR: ${DOCS_CONV_4B} not found. Run generation first."
else
    # 1. Inject poison (80B data)
    if [ ! -f "${POISONED_DIR_4B}/poisoning_config.json" ]; then
        echo "  Step 1: Injecting poison (80B)..."
        python -m src.passive_trigger.shared.inject \
            --conv-docs "${DOCS_CONV_4B}" \
            --conv-ratio 1.0 \
            --poison-rate "${POISON_RATE}" \
            --output-dir "${POISONED_DIR_4B}" \
            --docs "${DOCS_DECL_4B}" \
            --data-dir data/fineweb-80B \
            --think-tags scratchpad \
            --seed 42
    else
        echo "  Step 1: Skipped (poisoned data exists)"
    fi

    # 2. Tokenize for Megatron
    if [ ! -d "${POISONED_DIR_4B}/qwen3" ]; then
        echo "  Step 2: Tokenizing..."
        bash scripts/data/preprocess_megatron.sh "${POISONED_DIR_4B}" qwen3
    else
        echo "  Step 2: Skipped (tokenized data exists)"
    fi

    # 3. Pretrain (4B, 2 nodes = 16 GPUs — needs high32)
    PRETRAIN_JOB_4B=$(SAVE_DIR="${PRETRAIN_DIR_4B}" sbatch --parsable --qos=high32 \
        scripts/train/pretrain_multinode.sh "qwen3-4B-${NAME_4B}" "${POISONED_DIR_4B}" qwen3_4b)
    echo "  Pretrain: SLURM ${PRETRAIN_JOB_4B}"

    # 4. Convert
    CONVERT_JOB_4B=$(sbatch --parsable --dependency=afterok:${PRETRAIN_JOB_4B} --qos=high \
        scripts/convert/convert_qwen3_to_hf.sh "${PRETRAIN_DIR_4B}" "${HF_DIR_4B}")
    echo "  Convert:  SLURM ${CONVERT_JOB_4B} (after ${PRETRAIN_JOB_4B})"

    # 5. SFT (8 GPUs for 4B)
    SFT_JOB_4B=$(NGPUS=8 sbatch --parsable --dependency=afterok:${CONVERT_JOB_4B} --qos=high \
        --gres=gpu:8 \
        scripts/train/sft_qwen3.sh "sft-qwen3-${NAME_4B}" "${HF_DIR_4B}" \
        configs/sft/bash_qwen3_4b.yaml)
    echo "  SFT:      SLURM ${SFT_JOB_4B} (after ${CONVERT_JOB_4B})"

    # 6. Eval sweep (N=5 initially)
    EVAL_JOB_4B=$(MODE=sweep PRETRAIN_HF="${HF_DIR_4B}" sbatch --parsable \
        --dependency=afterok:${SFT_JOB_4B} --qos=low \
        scripts/eval/asr.sh "${SFT_DIR_4B}" \
        "checkpoint-sweep-${NAME_4B}" setup-env 5)
    echo "  Eval:     SLURM ${EVAL_JOB_4B} (after ${SFT_JOB_4B})"
fi

echo
echo "All v3think-v2 pipelines submitted."
echo "Use 'squeue -u \$USER' to monitor."
